import { confirmDoubleOptInSubscription } from "~/server/service/double-opt-in-service";
import { redirect } from "next/navigation";

export const dynamic = "force-dynamic";

const PUBLIC_CONFIRMATION_ERRORS = new Set([
  "Invalid confirmation link",
  "Confirmation link has expired",
  "Contact not found",
]);

function getConfirmationErrorMessage(error: unknown) {
  if (error instanceof Error && PUBLIC_CONFIRMATION_ERRORS.has(error.message)) {
    return error.message;
  }

  return "Unable to confirm your subscription.";
}

function buildSubscribeUrl({
  contactId,
  expiresAt,
  hash,
  status,
  error,
}: {
  contactId?: string;
  expiresAt?: string;
  hash?: string;
  status?: "success" | "error";
  error?: string;
}) {
  const searchParams = new URLSearchParams();

  if (contactId) searchParams.set("contactId", contactId);
  if (expiresAt) searchParams.set("expiresAt", expiresAt);
  if (hash) searchParams.set("hash", hash);
  if (status) searchParams.set("status", status);
  if (error) searchParams.set("error", error);

  const queryString = searchParams.toString();
  return queryString ? `/subscribe?${queryString}` : "/subscribe";
}

async function confirmSubscriptionAction(formData: FormData) {
  "use server";

  const contactId = formData.get("contactId");
  const expiresAt = formData.get("expiresAt");
  const hash = formData.get("hash");

  if (
    typeof contactId !== "string" ||
    typeof expiresAt !== "string" ||
    typeof hash !== "string"
  ) {
    redirect(
      buildSubscribeUrl({
        status: "error",
        error: "Invalid confirmation link",
      }),
    );
  }

  let redirectUrl: string;

  try {
    await confirmDoubleOptInSubscription({
      contactId,
      expiresAt,
      hash,
    });

    redirectUrl = buildSubscribeUrl({
      status: "success",
    });
  } catch (error) {
    redirectUrl = buildSubscribeUrl({
      contactId,
      expiresAt,
      hash,
      status: "error",
      error: getConfirmationErrorMessage(error),
    });
  }

  redirect(redirectUrl);
}

export default async function SubscribePage({
  searchParams,
}: {
  searchParams: Promise<{ [key: string]: string | string[] | undefined }>;
}) {
  const getSingleValue = (value: string | string[] | undefined) =>
    Array.isArray(value) ? value[0] : value;

  const params = await searchParams;
  const contactId = getSingleValue(params.contactId);
  const expiresAt = getSingleValue(params.expiresAt);
  const hash = getSingleValue(params.hash);
  const status = getSingleValue(params.status);
  const error = getSingleValue(params.error);

  const expiresAtTimestamp = Number(expiresAt);
  const hasValidExpiry = Number.isFinite(expiresAtTimestamp);
  const isExpired = hasValidExpiry && Date.now() > expiresAtTimestamp;
  const normalizedError =
    status === "error"
      ? getConfirmationErrorMessage(error ? new Error(error) : null)
      : null;
  const isFatalError =
    normalizedError === "Invalid confirmation link" ||
    normalizedError === "Confirmation link has expired" ||
    normalizedError === "Contact not found";

  if (status === "success") {
    return (
      <div className="min-h-screen flex items-center justify-center p-6">
        <div className="max-w-md w-full space-y-4 p-8 shadow rounded-xl border">
          <h1 className="text-2xl font-semibold text-center">
            Subscription Confirmed
          </h1>
          <p className="text-sm text-muted-foreground text-center">
            Your subscription is confirmed and you will receive future emails.
          </p>
        </div>
      </div>
    );
  }

  if (status === "error" && (!contactId || !expiresAt || !hash)) {
    return (
      <div className="min-h-screen flex items-center justify-center p-6">
        <div className="max-w-md w-full space-y-4 p-8 shadow rounded-xl border">
          <h1 className="text-2xl font-semibold text-center">
            Confirmation Failed
          </h1>
          <p className="text-sm text-muted-foreground text-center">
            {normalizedError ?? "Unable to confirm your subscription."}
          </p>
        </div>
      </div>
    );
  }

  if (!contactId || !expiresAt || !hash || !hasValidExpiry) {
    return (
      <div className="min-h-screen flex items-center justify-center p-6">
        <div className="max-w-md w-full space-y-4 p-8 shadow rounded-xl border">
          <h1 className="text-2xl font-semibold text-center">Invalid Link</h1>
          <p className="text-sm text-muted-foreground text-center">
            This confirmation link is invalid. Please request a new one.
          </p>
        </div>
      </div>
    );
  }

  if (isExpired) {
    return (
      <div className="min-h-screen flex items-center justify-center p-6">
        <div className="max-w-md w-full space-y-4 p-8 shadow rounded-xl border">
          <h1 className="text-2xl font-semibold text-center">
            Confirmation Failed
          </h1>
          <p className="text-sm text-muted-foreground text-center">
            Confirmation link has expired
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex items-center justify-center p-6">
      <div className="max-w-md w-full space-y-4 p-8 shadow rounded-xl border">
        <h1 className="text-2xl font-semibold text-center">
          Confirm Subscription
        </h1>
        <p className="text-sm text-muted-foreground text-center">
          Click the button below to confirm your subscription.
        </p>

        {normalizedError ? (
          <p className="text-sm text-red text-center">{normalizedError}</p>
        ) : null}

        {!isFatalError ? (
          <form action={confirmSubscriptionAction} className="pt-2">
            <input type="hidden" name="contactId" value={contactId} />
            <input type="hidden" name="expiresAt" value={expiresAt} />
            <input type="hidden" name="hash" value={hash} />
            <button
              type="submit"
              className="w-full rounded-md bg-primary px-4 py-2 text-sm font-medium text-primary-foreground hover:bg-primary/90"
            >
              Confirm subscription
            </button>
          </form>
        ) : null}
      </div>
    </div>
  );
}

# Forms & Controls

Inputs, buttons, forms, and interactive controls.

## Inputs

### Labels

Clicking the input label should focus the input field. Always associate labels with inputs:

```html
<label for="email">Email</label>
<input id="email" type="email" />

<!-- Or wrap the input -->
<label>
  Email
  <input type="email" />
</label>
```

### Input Types

Use appropriate `type` attributes:

```html
<input type="email" />
<input type="password" />
<input type="tel" />
<input type="url" />
<input type="number" />
<input type="search" />
```

### Autocomplete and Spellcheck

Disable `spellcheck` and `autocomplete` most of the time for cleaner UX:

```html
<input
  type="text"
  spellcheck="false"
  autocomplete="off"
/>
```

### 1Password Integration

Disable 1Password autocomplete when not needed:

```html
<input data-lpignore="true" data-1p-ignore />
```

### Input Decorations

Prefix and suffix decorations (icons, labels) should be:
- Absolutely positioned on top of the text input with padding
- Not placed next to the input as siblings
- Should trigger focus on the input when clicked

```css
.input-wrapper {
  position: relative;
}

.input-icon {
  position: absolute;
  left: 12px;
  top: 50%;
  transform: translateY(-50%);
  pointer-events: none;
}

.input-field {
  padding-left: 40px;
}
```

For clickable icons (like clear button):

```jsx
<button
  className="input-icon-button"
  onClick={() => inputRef.current?.focus()}
>
  <SearchIcon />
</button>
```

### Font Size (iOS)

Ensure input font size is at least 16px to prevent zooming on iOS:

```css
input, textarea, select {
  font-size: 16px;
}
```

Inputs smaller than 16px cause iOS Safari to zoom in on focus.

### Autofocus

- Autofocus on inputs when a modal opens (if an input exists in the modal)
- Do NOT autofocus inputs on touch devices—it opens the keyboard unexpectedly

```jsx
// Check for touch device before autofocus
const isTouchDevice = 'ontouchstart' in window;

<input autoFocus={!isTouchDevice} />
```

## Forms

### Form Wrapper

Inputs should be wrapped with a `<form>` to submit by pressing Enter:

```html
<form onSubmit={handleSubmit}>
  <input type="text" />
  <button type="submit">Submit</button>
</form>
```

### Keyboard Submission

Ensure `Cmd+Enter` (Mac) / `Ctrl+Enter` (Windows) submits the form, especially for textareas:

```jsx
function handleKeyDown(e) {
  if ((e.metaKey || e.ctrlKey) && e.key === 'Enter') {
    handleSubmit();
  }
}
```

### Prefilling Forms

- Use logged-in user's data to prefill forms when possible
- When linking to a form, prefill content based on the request context

Example: If a user clicks "Change username", prefill with:
> "I'd like to change my username to:"

If you can prefill any user data based on the logged-in user, do that.

## Buttons

### Semantic Elements

A button should always be a `<button>`. Don't add click events on elements that aren't buttons:

```html
<!-- Good -->
<button onClick={handleClick}>Click me</button>

<!-- Bad -->
<div onClick={handleClick}>Click me</div>
<span onClick={handleClick}>Click me</span>
```

### Disabled After Submission

Disable buttons after submission to avoid duplicate network requests:

```jsx
const [isSubmitting, setIsSubmitting] = useState(false);

<button
  disabled={isSubmitting}
  onClick={async () => {
    setIsSubmitting(true);
    await submitForm();
    setIsSubmitting(false);
  }}
>
  {isSubmitting ? 'Submitting...' : 'Submit'}
</button>
```

### Button Shortcuts

If a button's action can also be performed with a keyboard shortcut, show that shortcut as a tooltip on the button:

```jsx
<Tooltip content="Save (Cmd+S)">
  <button onClick={save}>Save</button>
</Tooltip>
```

### Button Press Feel

Add `transform: scale(0.97)` on `:active` to make buttons feel responsive:

```css
.button:active {
  transform: scale(0.97);
}
```

## Checkboxes and Controls

### Dead Zones

Avoid dead zones on checkboxes and controls. The space between label and control should also be clickable:

```css
.checkbox-wrapper {
  display: flex;
  align-items: center;
  gap: 8px;
  cursor: pointer;
}

/* Make the entire row clickable, not just the checkbox */
.checkbox-wrapper label {
  cursor: pointer;
  flex: 1;
}
```

Or use a label that wraps everything:

```html
<label class="checkbox-row">
  <input type="checkbox" />
  <span>Remember me</span>
</label>
```

## Destructive Actions

Ensure destructive actions require confirmation:

```jsx
function handleDelete() {
  if (confirm('Are you sure you want to delete this?')) {
    deleteItem();
  }
}
```

For better UX, use a proper confirmation modal instead of `confirm()`.

## Component Libraries

Use Base UI for accessible component primitives. If it doesn't fit the codebase, use whatever else fits, but ensure accessibility is maintained.

## Error Handling

Colocate errors—show error messages close to the field that caused them:

```jsx
<div className="field">
  <input type="email" aria-invalid={!!error} />
  {error && <span className="error">{error}</span>}
</div>
```
# Touch & Accessibility

Touch devices, mobile considerations, keyboard navigation, and accessibility.

## Touch Devices

### Hover Effects

Disable hover effects on touch devices. Touch devices trigger hover on tap, causing false positives:

```css
/* Only apply hover on devices that support it */
@media (hover: hover) and (pointer: fine) {
  .element:hover {
    transform: scale(1.05);
  }
}
```

**Important:** Don't rely on hover effects for the UI to work properly. Hover should enhance, not enable functionality.

### Touch Action

Disable `touch-action` for custom components that implement pan and zoom gestures to prevent interference from native behavior:

```css
.custom-canvas {
  touch-action: none;
}
```

### Double-Tap Zoom

Set `touch-action: manipulation` to prevent double-tap zoom on controls:

```css
button, a, input {
  touch-action: manipulation;
}
```

### Tap Targets

Ensure minimal tap target of all buttons on touch devices is at least 44px:

```css
.icon-button {
  /* Visual size can be smaller */
  width: 24px;
  height: 24px;
  position: relative;
}

/* But hit area should be 44px */
.icon-button::before {
  content: '';
  position: absolute;
  inset: -10px;
}
```

Or use padding:

```css
.small-button {
  min-width: 44px;
  min-height: 44px;
  display: flex;
  align-items: center;
  justify-content: center;
}
```

### Video Autoplay

Apply `muted` and `playsinline` to `<video>` tags to autoplay on iOS without opening a fullscreen video popup:

```html
<video autoplay muted playsinline loop>
  <source src="video.mp4" type="video/mp4" />
</video>
```

### OS-Specific Shortcuts

Replace `Cmd` with `Ctrl` based on operating system:

```js
const isMac = navigator.platform.toUpperCase().indexOf('MAC') >= 0;
const modKey = isMac ? 'Cmd' : 'Ctrl';

// Display: "Save (Cmd+S)" on Mac, "Save (Ctrl+S)" on Windows
```

## Keyboard Navigation

### Tab Order

Tabbing should work consistently across the site. Users should only be able to tab through visible elements:

```css
/* Hide from tab order when not visible */
.hidden-panel {
  visibility: hidden;
}

/* Or use inert attribute */
<div inert={!isVisible}>...</div>
```

### Scroll Into View

Ensure keyboard navigation scrolls elements into view if needed:

```jsx
function handleFocus(e) {
  e.target.scrollIntoView({
    behavior: 'smooth',
    block: 'nearest',
  });
}
```

### Focus Management

When opening modals or dialogs, move focus to the first interactive element or the modal itself. When closing, return focus to the trigger element.

## Accessibility

### ARIA Labels

Always set aria labels on buttons with an icon as content:

```html
<button aria-label="Close dialog">
  <CloseIcon />
</button>

<button aria-label="Search">
  <SearchIcon />
</button>
```

### Code Illustrations

Illustrations built in code should have proper `aria-label` attribute:

```jsx
<div
  role="img"
  aria-label="Abstract geometric pattern"
  className="decorative-illustration"
/>
```

### Reduced Motion

See [animations.md](animations.md) for `prefers-reduced-motion` implementation. Every animation needs reduced motion support.

### Videos

For users who prefer reduced motion, show play buttons instead of autoplaying videos:

```jsx
const prefersReducedMotion = window.matchMedia(
  '(prefers-reduced-motion: reduce)'
).matches;

<video
  autoPlay={!prefersReducedMotion}
  controls={prefersReducedMotion}
  muted
  playsinline
/>
```

### Time-Limited Actions

Ensure any time-limited action is frozen when the user switches tabs. Use the `visibilitychange` event:

```js
let timeoutId;
let remainingTime;
let startTime;

document.addEventListener('visibilitychange', () => {
  if (document.hidden) {
    // Pause the timer
    clearTimeout(timeoutId);
    remainingTime -= Date.now() - startTime;
  } else {
    // Resume the timer
    startTime = Date.now();
    timeoutId = setTimeout(callback, remainingTime);
  }
});
```

## Feedback

Ensure feedback components are visible on the page. Feedback is important—don't hide it behind hover states or modals.

## Tooltips

### Delay and Animation

Tooltips should have a delay before appearing to prevent accidental activation:

```css
.tooltip {
  transition-delay: 200ms;
}
```

**Sequential tooltips:** Once a tooltip is open, hovering over other tooltips should open them with no delay and no animation. Track "warm" state:

```jsx
const [isWarm, setIsWarm] = useState(false);

// When any tooltip opens, set warm state
// Clear warm state after 300ms of no tooltip being open
```

### Submenus

Apply a safe-area for submenus using clippath to ensure diagonal movement works. Users should be able to move diagonally from parent menu to submenu without the submenu closing.

```css
.submenu-trigger::after {
  content: '';
  position: absolute;
  /* Creates a "safe zone" for cursor movement */
  clip-path: polygon(0 0, 100% 0, 100% 100%);
  /* Adjust based on submenu position */
}
```

import * as React from "react";
import { Slot } from "@radix-ui/react-slot";
import { cva, type VariantProps } from "class-variance-authority";
import { Spinner } from "./spinner";

import { cn } from "../lib/utils";

const buttonVariants = cva(
  "inline-flex items-center justify-center whitespace-nowrap rounded-md text-sm font-medium ring-offset-background transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-border  disabled:pointer-events-none disabled:opacity-50",
  {
    variants: {
      variant: {
        default: "bg-primary text-primary-foreground hover:bg-primary/90",
        destructive:
          "bg-destructive text-destructive-foreground hover:bg-destructive/90",
        outline:
          "border border-input bg-background hover:bg-accent hover:text-accent-foreground",
        secondary:
          "bg-secondary text-secondary-foreground hover:bg-secondary/80",
        ghost: "hover:bg-accent hover:text-accent-foreground",
        icon: "bg-transparent hover:bg-transparent hover:bg-accent hover:text-accent-foreground",
        link: "text-primary underline-offset-4 hover:underline",
        silent: "bg-transparent hover:bg-accent/10 p-1",
      },
      size: {
        default: "h-9 px-4 ",
        sm: "h-8 rounded-md px-3",
        lg: "h-10 rounded-md px-8",
        icon: "h-10 w-10",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  },
);

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {
  asChild?: boolean;
  isLoading?: boolean;
  showSpinner?: boolean;
}

const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  (
    {
      className,
      variant,
      size,
      asChild = false,
      isLoading,
      children,
      showSpinner = false,
      ...props
    },
    ref,
  ) => {
    const Comp = asChild ? Slot : "button";

    return (
      <Comp
        className={cn(buttonVariants({ variant, size, className }))}
        ref={ref}
        disabled={isLoading || props.disabled}
        {...props}
      >
        {asChild ? (
          children
        ) : (
          <>
            {isLoading && showSpinner ? (
              <Spinner className="h-4 w-4 mr-2 " innerSvgClass="stroke-white" />
            ) : null}
            {children}
          </>
        )}
      </Comp>
    );
  },
);
Button.displayName = "Button";

export { Button, buttonVariants };
